        AdminPage::open('FieldFlow Growth Hub', 'Centro de formação, certificação, badges, missões e desenvolvimento das equipas de terreno.');
        echo '<style>.ffp-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:16px}.ffp-card{background:#fff;border:1px solid #dbe3ef;border-radius:18px;padding:18px;box-shadow:0 10px 26px rgba(15,23,42,.06)}.ffp-kpi strong{display:block;font-size:34px;letter-spacing:-.04em}.ffp-tabs{display:flex;gap:8px;flex-wrap:wrap;margin:18px 0}.ffp-tabs a{padding:9px 13px;border-radius:999px;background:#fff;border:1px solid #dbe3ef;text-decoration:none}.ffp-tabs a.active{background:#0f172a;color:#fff;border-color:#0f172a}.ffp-form-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}.ffp-table{margin-top:16px}.ffp-pill{display:inline-block;border-radius:999px;padding:3px 8px;background:#eef2ff;color:#3730a3;font-size:12px}.ffp-muted{color:#64748b}.ffp-lesson-box{border:1px solid #e2e8f0;border-radius:16px;padding:12px;background:#f8fafc;margin:10px 0}.ffp-small{font-size:12px;color:#64748b}.ffp-actions{display:flex;gap:8px;flex-wrap:wrap}.ffp-actions a{font-size:12px}.ffp-danger{color:#b91c1c!important}.ffp-editing{border-color:#f59e0b!important;box-shadow:0 0 0 2px rgba(245,158,11,.12),0 10px 26px rgba(15,23,42,.06)!important}</style>';
        if ($tab === 'academy' || $tab === 'media' || $tab === 'missions') {
            echo <<<'HTML'
<style>
/* FieldFlow Growth Hub BO polish, conservative admin-only layer */
.ffp-card{box-sizing:border-box}.ffp-card h2{margin-top:0;font-size:20px;line-height:1.25}.ffp-card h3{margin:22px 0 8px;font-size:15px;text-transform:uppercase;letter-spacing:.04em;color:#334155}.ffp-card p{margin-top:8px;margin-bottom:12px}.ffp-card label{font-weight:600;color:#1e293b}.ffp-card input.regular-text,.ffp-card select,.ffp-card textarea{margin-top:6px;border-color:#cbd5e1;border-radius:8px}.ffp-card input.regular-text:focus,.ffp-card select:focus,.ffp-card textarea:focus{border-color:#0f172a;box-shadow:0 0 0 1px #0f172a}.ffp-form-grid{align-items:end}.ffp-lesson-box{position:relative;background:#fff;border-color:#d8e0ec;border-radius:14px;padding:14px 14px 10px;margin:12px 0}.ffp-lesson-box:before{content:'Learning Experience';display:block;margin:-2px 0 10px;font-size:11px;font-weight:800;letter-spacing:.08em;text-transform:uppercase;color:#64748b}.ffp-lesson-box .ffp-form-grid{grid-template-columns:80px minmax(260px,1.4fr) 150px minmax(260px,1.3fr) 100px 150px 170px;gap:10px}.ffp-lesson-box p{margin:0 0 10px}.ffp-lesson-box textarea{min-height:54px}.ffp-table table.widefat{border-radius:12px;overflow:hidden;border-color:#dbe3ef}.ffp-table table.widefat th{background:#f8fafc;color:#334155;font-weight:700}.ffp-table table.widefat td{vertical-align:middle}.ffp-actions{align-items:center}.ffp-actions a{display:inline-flex;align-items:center;padding:4px 8px;border-radius:999px;background:#f8fafc;border:1px solid #e2e8f0;text-decoration:none}.ffp-actions a:hover{background:#eef2ff;border-color:#c7d2fe}.ffp-actions a.ffp-danger{background:#fff7f7;border-color:#fecaca}.ffp-pill{font-weight:700}.ffp-editing{outline:2px solid rgba(245,158,11,.25)}.ffp-preview{background:#f8fafc;border:1px solid #dbe3ef;border-radius:18px;padding:18px;margin:12px 0}.ffp-preview-hero{background:linear-gradient(135deg,#0f172a,#1e293b);color:#fff;border-radius:18px;padding:22px}.ffp-preview-hero h2{color:#fff;margin:0 0 6px}.ffp-preview-list{margin:14px 0 0}.ffp-preview-item{background:#fff;border:1px solid #e2e8f0;border-radius:14px;padding:12px;margin:8px 0;display:flex;justify-content:space-between;gap:12px}.ffp-dup-box{background:#f8fafc;border:1px solid #e2e8f0;border-radius:14px;padding:12px;margin-top:12px}
