@media(max-width:782px){.ffp-tabs a{width:100%;text-align:center}.ffp-card{padding:14px}.ffp-lesson-box .ffp-form-grid{grid-template-columns:1fr}.ffp-card input.regular-text,.ffp-card select,.ffp-card textarea{width:100%}}
