HTML;
        }

        echo '<div class="ffp-tabs">'; foreach($tabs as $key=>$label){$url=admin_url('admin.php?page=routespro-performance&tab='.$key); echo '<a class="'.esc_attr($tab===$key?'active':'').'" href="'.esc_url($url).'">'.esc_html($label).'</a>'; } echo '</div>';
