    private static function dashboard(): void {
        $stats=Module::stats(); $top=Module::top_performers();
        echo '<div class="ffp-grid">'; self::kpi('Missões atribuídas',$stats['assigned'],'Volume operacional criado'); self::kpi('Taxa de conclusão',$stats['completion_rate'].'%','Execução das missões'); self::kpi('Skill Score',$stats['avg_score'],'Evolução das competências'); self::kpi('Cursos ativos',$stats['courses'],'Conteúdo de formação'); echo '</div>';
        echo '<div class="ffp-grid" style="margin-top:16px"><div class="ffp-card"><h2>Academy Enterprise 1.0</h2><p>Suporta conteúdos de formação em Canva, YouTube, PDF e links externos, mantendo o FieldFlow atual intacto.</p><ul><li>Cursos por cliente e campanha.</li><li>Lições multimédia com conclusão pelo operacional.</li><li>Missões ligadas a cursos.</li><li>Biblioteca Media reutilizável.</li></ul></div><div class="ffp-card"><h2>Top performers</h2>';
        if(!$top) echo '<p class="ffp-muted">Ainda sem dados do Growth Hub.</p>'; else { echo '<table class="widefat striped"><thead><tr><th>Utilizador</th><th>Concluídas</th><th>Score</th></tr></thead><tbody>'; foreach($top as $r){ echo '<tr><td>'.esc_html($r['display_name']).'</td><td>'.esc_html((string)$r['completed']).'</td><td>'.esc_html((string)round((float)$r['avg_score'])).'</td></tr>'; } echo '</tbody></table>'; }
        echo '</div></div>';
    }

    private static function kpi(string $label, $value, string $small): void { echo '<div class="ffp-card ffp-kpi"><span>'.esc_html($label).'</span><strong>'.esc_html((string)$value).'</strong><small class="ffp-muted">'.esc_html($small).'</small></div>'; }

    private static function academy(): void {
        $clients=Module::get_clients(); $projects=Module::get_projects(); $courses=Module::get_courses(['include_inactive'=>1]);
        $edit_id=absint($_GET['edit'] ?? 0); $edit=$edit_id ? Module::get_course($edit_id) : null; $lessons=$edit ? Module::get_lessons($edit_id) : [];
        echo '<div class="ffp-card '.($edit?'ffp-editing':'').'"><h2>'.($edit?'Editar curso Academy':'Novo curso Academy').'</h2><p class="ffp-muted">Academy UX Pro: cria experiências de aprendizagem ordenadas, obrigatórias ou opcionais, com tempo mínimo de consumo e estado de publicação.</p><form method="post" action="'.esc_url(admin_url('admin-post.php')).'">';
        wp_nonce_field('fieldflow_perf_save_course'); echo '<input type="hidden" name="action" value="fieldflow_perf_save_course"><input type="hidden" name="course_id" value="'.esc_attr((string)$edit_id).'">';
        echo '<div class="ffp-form-grid"><p><label>Cliente<br><select name="client_id"><option value="0">Global</option>'; foreach($clients as $c) echo '<option value="'.esc_attr($c['id']).'" '.selected((int)($edit['client_id']??0),(int)$c['id'],false).'>'.esc_html($c['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Campanha<br><select name="project_id"><option value="0">Todas</option>'; foreach($projects as $p) echo '<option value="'.esc_attr($p['id']).'" '.selected((int)($edit['project_id']??0),(int)$p['id'],false).'>'.esc_html($p['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Título<br><input class="regular-text" name="title" required value="'.esc_attr($edit['title']??'').'" placeholder="Retail Excellence Program"></label></p><p><label>Duração total min.<br><input type="number" name="duration_min" value="'.esc_attr((string)($edit['duration_min']??15)).'"></label></p><p><label>Pontos<br><input type="number" name="points" value="'.esc_attr((string)($edit['points']??100)).'"></label></p><p><label>Estado<br><select name="status"><option value="active" '.selected(($edit['status']??'active'),'active',false).'>Publicado</option><option value="draft" '.selected(($edit['status']??''),'draft',false).'>Rascunho</option><option value="archived" '.selected(($edit['status']??''),'archived',false).'>Arquivado</option></select></label></p></div>';
        echo '<p><label>Descrição<br><textarea name="description" rows="4" class="large-text" placeholder="Objetivo, aplicação no terreno e resultado esperado.">'.esc_textarea($edit['description']??'').'</textarea></label></p>';
        echo '<h3>Learning Experiences</h3><p class="ffp-muted">Define a ordem, se a lição conta para certificação e o tempo mínimo antes de permitir conclusão. Para conteúdo texto, podes deixar o URL vazio.</p>';
        if($edit && isset($_GET['preview'])) self::academy_preview($edit, $lessons);
        $rows=max(5,count($lessons)+1); for($i=0;$i<$rows;$i++){ $l=$lessons[$i]??[]; $idx=$i+1; echo '<div class="ffp-lesson-box">'; if(!empty($l['id'])){ $up=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_move_lesson&course_id='.$edit_id.'&lesson_id='.(int)$l['id'].'&dir=up'),'fieldflow_perf_move_lesson_'.(int)$l['id']); $down=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_move_lesson&course_id='.$edit_id.'&lesson_id='.(int)$l['id'].'&dir=down'),'fieldflow_perf_move_lesson_'.(int)$l['id']); echo '<div class="ffp-actions" style="justify-content:flex-end;margin-bottom:8px"><a href="'.esc_url($up).'">Subir</a><a href="'.esc_url($down).'">Descer</a></div>'; } echo '<div class="ffp-form-grid"><p><label>Ordem<br><input type="number" name="lesson_order[]" value="'.esc_attr((string)($l['sort_order']??$idx)).'" style="width:90px"></label></p><p><label>Título da lição<br><input class="regular-text" name="lesson_title[]" value="'.esc_attr($l['title']??'').'" placeholder="Ex: Argumentar valor sem desconto"></label></p><p><label>Tipo<br><select name="lesson_type[]">'; $types=['auto'=>'Automático','canva'=>'Canva','youtube'=>'YouTube','pdf'=>'PDF','link'=>'Link externo','text'=>'Texto rico']; foreach($types as $k=>$v) echo '<option value="'.esc_attr($k).'" '.selected(($l['content_type']??'auto'),$k,false).'>'.esc_html($v).'</option>'; echo '</select></label></p><p><label>URL<br><input class="regular-text" name="lesson_url[]" value="'.esc_attr($l['media_url']??'').'" placeholder="https://..."></label></p><p><label>Minutos<br><input type="number" name="lesson_min[]" value="'.esc_attr((string)($l['estimated_min']??3)).'" style="width:90px"></label></p><p><label>Tempo mínimo segundos<br><input type="number" name="lesson_min_watch[]" value="'.esc_attr((string)($l['min_watch_seconds']??8)).'" style="width:120px"></label></p><p><label><input type="hidden" name="lesson_required['.$i.']" value="0"><input type="checkbox" name="lesson_required['.$i.']" value="1" '.checked((int)($l['is_required']??1),1,false).'> Obrigatória para concluir</label></p></div><p><label>Notas da lição<br><textarea name="lesson_body[]" rows="2" class="large-text" placeholder="O que o operacional deve reter desta experiência.">'.esc_textarea($l['body']??'').'</textarea></label></p></div>'; }
        echo '<p><button class="button button-primary">'.($edit?'Guardar alterações':'Criar curso Academy').'</button> '.($edit?'<a class="button" href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=academy')).'">Cancelar edição</a> <a class="button" href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=academy&edit='.$edit_id.'&preview=1')).'">Pré-visualizar curso</a>':'').'</p></form></div>';
        echo '<div class="ffp-card"><h2>Duplicar curso para outra campanha</h2><p class="ffp-muted">Copia um curso completo, com lições e regras, para outro cliente/campanha. Fica em rascunho por segurança.</p><form method="post" action="'.esc_url(admin_url('admin-post.php')).'">'; wp_nonce_field('fieldflow_perf_duplicate_course_to_scope'); echo '<input type="hidden" name="action" value="fieldflow_perf_duplicate_course_to_scope"><div class="ffp-form-grid"><p><label>Curso origem<br><select name="course_id">'; foreach($courses as $dc) echo '<option value="'.esc_attr($dc['id']).'">#'.esc_html($dc['id']).' '.esc_html($dc['title']).'</option>'; echo '</select></label></p><p><label>Cliente destino<br><select name="target_client_id"><option value="0">Global</option>'; foreach($clients as $c) echo '<option value="'.esc_attr($c['id']).'">'.esc_html($c['name']).'</option>'; echo '</select></label></p><p><label>Campanha destino<br><select name="target_project_id"><option value="0">Todas</option>'; foreach($projects as $p) echo '<option value="'.esc_attr($p['id']).'">'.esc_html($p['name']).'</option>'; echo '</select></label></p><p><label>Estado destino<br><select name="target_status"><option value="draft">Rascunho</option><option value="active">Publicado</option></select></label></p></div><p><button class="button">Duplicar para campanha</button></p></form></div>';
        echo '<div class="ffp-card ffp-table"><h2>Cursos</h2><table class="widefat striped"><thead><tr><th>ID</th><th>Título</th><th>Âmbito</th><th>Lições</th><th>Pontos</th><th>Estado</th><th>Ações</th></tr></thead><tbody>';
        foreach($courses as $r){ $edit_url=admin_url('admin.php?page=routespro-performance&tab=academy&edit='.(int)$r['id']); $dup_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_duplicate_course&id='.(int)$r['id']),'fieldflow_perf_duplicate_course_'.(int)$r['id']); $del_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_delete_course&id='.(int)$r['id']),'fieldflow_perf_delete_course_'.(int)$r['id']); echo '<tr><td>#'.esc_html($r['id']).'</td><td><strong>'.esc_html($r['title']).'</strong><br><span class="ffp-muted">'.esc_html(wp_trim_words(wp_strip_all_tags($r['description']??''),14)).'</span></td><td>Cliente '.esc_html((string)($r['client_id']?:'Global')).'<br>Campanha '.esc_html((string)($r['project_id']?:'Todas')).'</td><td>'.esc_html((string)($r['lessons_count']??0)).'</td><td>'.esc_html($r['points']).'</td><td><span class="ffp-pill">'.esc_html($r['status']).'</span></td><td><span class="ffp-actions"><a href="'.esc_url($edit_url).'">Editar</a><a href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=academy&edit='.(int)$r['id'].'&preview=1')).'">Preview</a><a href="'.esc_url($dup_url).'">Duplicar</a><a class="ffp-danger" href="'.esc_url($del_url).'" onclick="return confirm(\'Apagar este curso? As lições e progresso associado serão removidos.\')">Apagar</a></span></td></tr>'; }
        if(!$courses) echo '<tr><td colspan="7">Ainda sem cursos.</td></tr>'; echo '</tbody></table></div>';
    }


    private static function academy_preview(array $course, array $lessons): void {
        echo '<div class="ffp-preview"><div class="ffp-preview-hero"><h2>'.esc_html($course['title'] ?? 'Curso').'</h2><p>'.esc_html(wp_trim_words(wp_strip_all_tags($course['description'] ?? ''), 32)).'</p><small>'.esc_html((string)($course['duration_min'] ?? 0)).' min · '.esc_html((string)($course['points'] ?? 0)).' pontos · '.esc_html($course['status'] ?? 'active').'</small></div>';
        echo '<div class="ffp-preview-list">';
        if(!$lessons){ echo '<p class="ffp-muted">Sem lições para pré-visualizar.</p>'; }
        foreach($lessons as $i=>$l){
            $type=strtoupper((string)($l['content_type'] ?? 'link'));
            $required=!empty($l['is_required']) ? 'Obrigatória' : 'Opcional';
            echo '<div class="ffp-preview-item"><div><strong>'.esc_html(($i+1).'. '.($l['title'] ?? 'Lição')).'</strong><br><span class="ffp-muted">'.esc_html(wp_trim_words(wp_strip_all_tags($l['body'] ?? ''), 18)).'</span></div><div style="text-align:right"><span class="ffp-pill">'.esc_html($type).'</span><br><small class="ffp-muted">'.esc_html($required).' · '.esc_html((string)($l['estimated_min'] ?? 0)).' min</small></div></div>';
        }
        echo '</div></div>';
    }

