        wp_nonce_field('fieldflow_perf_save_media'); echo '<input type="hidden" name="action" value="fieldflow_perf_save_media"><input type="hidden" name="media_id" value="'.esc_attr((string)$edit_id).'">';
        echo '<div class="ffp-form-grid"><p><label>Cliente<br><select name="client_id"><option value="0">Global</option>'; foreach($clients as $c) echo '<option value="'.esc_attr($c['id']).'" '.selected((int)($edit['client_id']??0),(int)$c['id'],false).'>'.esc_html($c['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Campanha<br><select name="project_id"><option value="0">Todas</option>'; foreach($projects as $p) echo '<option value="'.esc_attr($p['id']).'" '.selected((int)($edit['project_id']??0),(int)$p['id'],false).'>'.esc_html($p['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Título<br><input class="regular-text" name="title" required value="'.esc_attr($edit['title']??'').'" placeholder="Apresentação produto"></label></p><p><label>Tipo<br><select name="media_type">'; $types=['auto'=>'Automático','canva'=>'Canva','youtube'=>'YouTube','pdf'=>'PDF','link'=>'Link externo']; foreach($types as $k=>$v) echo '<option value="'.esc_attr($k).'" '.selected(($edit['media_type']??'auto'),$k,false).'>'.esc_html($v).'</option>'; echo '</select></label></p><p><label>URL<br><input class="regular-text" name="media_url" required value="'.esc_attr($edit['media_url']??'').'" placeholder="https://..."></label></p><p><label>Estado<br><select name="status"><option value="active" '.selected(($edit['status']??'active'),'active',false).'>Ativo</option><option value="archived" '.selected(($edit['status']??''),'archived',false).'>Arquivado</option></select></label></p></div>';
        echo '<p><label>Notas<br><textarea name="notes" rows="3" class="large-text">'.esc_textarea($edit['notes']??'').'</textarea></label></p><p><button class="button button-primary">'.($edit?'Guardar alterações':'Guardar media').'</button> '.($edit?'<a class="button" href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=media')).'">Cancelar edição</a>':'').'</p></form></div>';
        echo '<div class="ffp-card ffp-table"><h2>Media guardada</h2><table class="widefat striped"><thead><tr><th>ID</th><th>Título</th><th>Tipo</th><th>Âmbito</th><th>URL</th><th>Ações</th></tr></thead><tbody>';
        foreach($items as $r){ $edit_url=admin_url('admin.php?page=routespro-performance&tab=media&edit='.(int)$r['id']); $del_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_delete_media&id='.(int)$r['id']),'fieldflow_perf_delete_media_'.(int)$r['id']); echo '<tr><td>#'.esc_html($r['id']).'</td><td><strong>'.esc_html($r['title']).'</strong><br><span class="ffp-muted">'.esc_html(wp_trim_words(wp_strip_all_tags($r['notes']??''),12)).'</span></td><td><span class="ffp-pill">'.esc_html($r['media_type']).'</span></td><td>Cliente '.esc_html((string)($r['client_id']?:'Global')).'<br>Campanha '.esc_html((string)($r['project_id']?:'Todas')).'</td><td><a href="'.esc_url($r['media_url']).'" target="_blank" rel="noopener">Abrir</a></td><td><span class="ffp-actions"><a href="'.esc_url($edit_url).'">Editar</a><a class="ffp-danger" href="'.esc_url($del_url).'" onclick="return confirm(\'Apagar este item da biblioteca?\')">Apagar</a></span></td></tr>'; }
