    }

    private static function missions(): void {
        $clients=Module::get_clients(); $projects=Module::get_projects(); $courses=Module::get_courses(); $users=Module::get_users_for_project(); $missions=Module::get_missions();
        $edit_id=absint($_GET['edit'] ?? 0); $edit=$edit_id ? Module::get_mission($edit_id) : null;
        echo '<div class="ffp-card '.($edit?'ffp-editing':'').'"><h2>'.($edit?'Editar missão operacional':'Nova missão operacional').'</h2><form method="post" action="'.esc_url(admin_url('admin-post.php')).'">'; wp_nonce_field('fieldflow_perf_save_mission'); echo '<input type="hidden" name="action" value="fieldflow_perf_save_mission"><input type="hidden" name="mission_id" value="'.esc_attr((string)$edit_id).'"><input type="hidden" name="replace_users" value="1">';
