ired" value="1" '.checked((int)($edit['evidence_required']??0),1,false).'> Exigir evidência</label></p><p><label><input type="checkbox" name="approval_required" value="1" '.checked((int)($edit['approval_required']??0),1,false).'> Exigir aprovação BO</label></p></div>';
