ab=missions')).'">Cancelar edição</a>':'').'</p></form></div>';
        echo '<div class="ffp-card ffp-table"><h2>Missões</h2><table class="widefat striped"><thead><tr><th>ID</th><th>Missão</th><th>Curso</th><th>Prazo</th><th>Pontos</th><th>Estado</th><th>Ações</th></tr></thead><tbody>'; foreach($missions as $r){ $edit_url=admin_url('admin.php?page=routespro-performance&tab=missions&edit='.(int)$r['id']); $del_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_delete_mission&id='.(int)$r['id']),'fieldflow_perf_delete_mission_'.(int)$r['id']); echo '<tr><td>#'.esc_html($r['id']).'</td><td><strong>'.esc_html($r['title']).'</strong><br><span class="ffp-muted">'.esc_html(wp_trim_words(wp_strip_all_tags($r['description']??''),16)).'</span></td><td>'.esc_html($r['course_title']?:'').'</td><td>'.esc_html($r['due_at']?:'Sem prazo').'</td><td>'.esc_html($r['points']).'</td><td><span class="ffp-pill">'.esc_html($r['status']).'</span></td><td><span class="ffp-actions"><a href="'.esc_url($edit_url).'">Editar</a><a class="ffp-danger" href="'.esc_url($del_url).'" onclick="return confirm(\'Apagar esta missão e as atribuições associadas?\')">Apagar</a></span></td></tr>'; } if(!$missions) echo '<tr><td colspan="7">Ainda sem missões.</td></tr>'; echo '</tbody></table></div>';
    }


    private static function mission_quiz_row(int $qi, array $q=[]): void {
        $opts=!empty($q['options'])&&is_array($q['options'])?implode("\n",$q['options']):'';
        $type=(string)($q['type']??'multiple');
        $types=['multiple'=>'Escolha múltipla','truefalse'=>'Verdadeiro/Falso','short'=>'Resposta curta','long'=>'Resposta longa','checklist'=>'Checklist','scale'=>'Escala 1-5','evidence'=>'Upload/Evidência'];
        echo '<tr class="ffp-quiz-row"><td><input class="regular-text" name="quiz_question[]" value="'.esc_attr($q['question']??'').'" placeholder="Ex: Qual é o primeiro passo?"><br><label><input type="checkbox" name="quiz_required['.esc_attr((string)$qi).']" value="1" '.checked((int)($q['required']??1),1,false).'> Obrigatória</label></td><td><select name="quiz_type[]">';
        foreach($types as $k=>$v) echo '<option value="'.esc_attr($k).'" '.selected($type,$k,false).'>'.esc_html($v).'</option>';
        echo '</select><p class="ffp-small">Checklist usa opções por linha. Escala cria 1 a 5.</p></td><td><textarea name="quiz_options[]" rows="4" placeholder="Uma opção por linha">'.esc_textarea($opts).'</textarea></td><td><input class="regular-text" name="quiz_answer[]" value="'.esc_attr($q['answer']??'').'" placeholder="Resposta certa ou itens esperados"><br><label>Pontos <input type="number" min="1" max="100" name="quiz_points[]" value="'.esc_attr((string)($q['points']??1)).'" style="width:80px"></label><br><input class="regular-text" name="quiz_feedback[]" value="'.esc_attr($q['feedback']??'').'" placeholder="Feedback opcional"></td><td><button type="button" class="button ffp-remove-question">Remover</button></td></tr>';
    }


