        echo '<p><label>Campanha<br><select name="project_id"><option value="0">Todas</option>'; foreach($projects as $pr) echo '<option value="'.esc_attr($pr['id']).'" '.selected((int)($edit['project_id']??0),(int)$pr['id'],false).'>'.esc_html($pr['name']).'</option>'; echo '</select></label></p>';
