        echo '<p><label>Valor<br><input name="compare_value" class="regular-text" value="'.esc_attr($edit['compare_value']??'').'" placeholder="Não"></label></p></div>';
        echo '<h3>Ações</h3><div class="ffp-form-grid"><p><label>Criar missão com título<br><input name="action_mission_title" class="regular-text" value="'.esc_attr($edit['action_mission_title']??'').'" placeholder="Corrigir implementação POS"></label></p>';
        echo '<p><label>Atribuir curso<br><select name="action_course_id"><option value="0">Nenhum</option>'; foreach($courses as $c) echo '<option value="'.esc_attr($c['id']).'" '.selected((int)($edit['action_course_id']??0),(int)$c['id'],false).'>'.esc_html($c['title']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Pontos da missão<br><input type="number" name="action_points" value="'.esc_attr((string)($edit['action_points']??100)).'"></label></p>';
        echo '<p><label><input type="checkbox" name="action_email" value="1" '.checked(!empty($edit['action_email']),true,false).'> Enviar email ao operacional</label></p></div>';
        echo '<p><label>Descrição da missão<br><textarea name="action_mission_description" rows="3" class="large-text">'.esc_textarea($edit['action_mission_description']??'').'</textarea></label></p>';
        echo '<div class="ffp-form-grid"><p><label>Assunto email<br><input name="email_subject" class="regular-text" value="'.esc_attr($edit['email_subject']??'Nova ação FieldFlow').'" ></label></p><p><label>Corpo email<br><textarea name="email_body" rows="3" class="large-text">'.esc_textarea($edit['email_body']??'Olá {{name}}, foi criada uma nova ação no FieldFlow com base no teu reporte.').'</textarea></label><br><span class="ffp-small">Variáveis: {{name}}, {{answer}}, {{rule}}, {{submission_id}}</span></p></div>';
        echo '<p><button class="button button-primary">'.($edit?'Guardar automação':'Criar automação').'</button> '.($edit?'<a class="button" href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=automations')).'">Cancelar edição</a>':'').'</p></form></div>';
        echo '<div class="ffp-card ffp-table"><h2>Regras de automação</h2><table class="widefat striped"><thead><tr><th>ID</th><th>Regra</th><th>Âmbito</th><th>Condição</th><th>Ações</th><th>Estado</th><th></th></tr></thead><tbody>';
        foreach($rules as $r){ $edit_url=admin_url('admin.php?page=routespro-performance&tab=automations&edit='.(int)$r['id']); $del_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_delete_automation&id='.(int)$r['id']),'fieldflow_perf_delete_automation_'.(int)$r['id']); $actions=[]; if(!empty($r['action_mission_title']))$actions[]='Missão'; if(!empty($r['action_course_id']))$actions[]='Curso'; if(!empty($r['action_email']))$actions[]='Email'; echo '<tr><td>#'.esc_html($r['id']).'</td><td><strong>'.esc_html($r['name']).'</strong></td><td>Cliente '.esc_html((string)($r['client_id']?:'Todos')).'<br>Campanha '.esc_html((string)($r['project_id']?:'Todas')).'</td><td>'.esc_html(($r['question_key']?:$r['question_label']).' '.$r['operator'].' '.$r['compare_value']).'</td><td>'.esc_html($actions?implode(' + ',$actions):'Sem ações').'</td><td><span class="ffp-pill">'.esc_html($r['status']).'</span></td><td><span class="ffp-actions"><a href="'.esc_url($edit_url).'">Editar</a><a class="ffp-danger" href="'.esc_url($del_url).'" onclick="return confirm(\'Apagar esta automação?\')">Apagar</a></span></td></tr>'; }
        if(!$rules) echo '<tr><td colspan="7">Ainda sem automações.</td></tr>'; echo '</tbody></table></div>';
        echo '<div class="ffp-card ffp-table"><h2>Histórico de automações</h2><table class="widefat striped"><thead><tr><th>Data</th><th>Regra</th><th>Operacional</th><th>Submissão</th><th>Ações</th></tr></thead><tbody>';
        foreach($logs as $l){ $actions=json_decode((string)($l['actions_json']??'[]'),true); $txt=[]; if(is_array($actions)){ foreach($actions as $a){ $txt[]=$a['type'] ?? 'ação'; }} echo '<tr><td>'.esc_html($l['created_at']).'</td><td>'.esc_html($l['rule_name']).'</td><td>'.esc_html($l['display_name']).'</td><td>#'.esc_html((string)$l['submission_id']).'</td><td>'.esc_html($txt?implode(', ',$txt):'Sem ações registadas').'</td></tr>'; }
        if(!$logs) echo '<tr><td colspan="5">Ainda sem histórico.</td></tr>'; echo '</tbody></table></div>';
    }


    private static function reset_engine(): void {
        $clients = Module::get_clients();
        $projects = Module::get_projects();
        $courses = Module::get_courses(['include_inactive'=>1]);
        $client_id = absint($_GET['client_id'] ?? 0);
        $project_id = absint($_GET['project_id'] ?? 0);
        $course_id = absint($_GET['course_id'] ?? 0);
        $user_id = absint($_GET['user_id'] ?? 0);
        $rows = Module::get_reset_engine_rows($client_id, $project_id, $course_id, $user_id);
        echo '<div class="ffp-card"><h2>Reset Engine</h2><p class="ffp-muted">Reinicia o progresso de formação de um operacional sem mexer nos cursos, missões ou reportes. O reset remove progresso e certificado desse curso e regista histórico auditável.</p>';
        if (!empty($_GET['reset'])) echo '<div class="notice notice-success inline"><p>Progresso reiniciado com sucesso.</p></div>';
        echo '<form method="get" action="'.esc_url(admin_url('admin.php')).'"><input type="hidden" name="page" value="routespro-performance"><input type="hidden" name="tab" value="reset"><div class="ffp-form-grid">';
        echo '<p><label>Cliente<br><select name="client_id"><option value="0">Todos</option>'; foreach($clients as $c) echo '<option value="'.esc_attr($c['id']).'" '.selected($client_id,(int)$c['id'],false).'>'.esc_html($c['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Campanha<br><select name="project_id"><option value="0">Todas</option>'; foreach($projects as $p) echo '<option value="'.esc_attr($p['id']).'" '.selected($project_id,(int)$p['id'],false).'>'.esc_html($p['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Curso<br><select name="course_id"><option value="0">Todos</option>'; foreach($courses as $c) echo '<option value="'.esc_attr($c['id']).'" '.selected($course_id,(int)$c['id'],false).'>'.esc_html($c['title']).'</option>'; echo '</select></label></p>';
        echo '<p><label>User ID opcional<br><input type="number" name="user_id" value="'.esc_attr((string)$user_id).'" placeholder="Ex: 12"></label></p>';
        echo '<p style="align-self:end"><button class="button button-primary">Filtrar</button> <a class="button" href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=reset')).'">Limpar</a></p></div></form></div>';
        echo '<div class="ffp-card ffp-table"><h2>Progresso por operacional</h2><table class="widefat striped"><thead><tr><th>Operacional</th><th>Curso</th><th>Âmbito</th><th>Progresso</th><th>Certificado</th><th>Reset</th></tr></thead><tbody>';
        foreach($rows as $r){
            echo '<tr><td><strong>'.esc_html($r['display_name']).'</strong><br><span class="ffp-muted">'.esc_html($r['user_email']).'</span></td><td>'.esc_html($r['course_title']).'</td><td>Cliente #'.esc_html((string)$r['client_id']).'<br>Campanha #'.esc_html((string)$r['project_id']).'</td><td><strong>'.esc_html((string)$r['progress']).'%</strong><br><span class="ffp-muted">'.esc_html((string)$r['done']).' / '.esc_html((string)$r['required']).' lições obrigatórias</span></td><td>'.($r['certificate_uid'] ? esc_html($r['certificate_uid']).'<br><span class="ffp-muted">'.esc_html($r['issued_at']).'</span>' : '<span class="ffp-muted">Sem certificado</span>').'</td><td><form method="post" action="'.esc_url(admin_url('admin-post.php')).'" onsubmit="return confirm(\'Reiniciar progresso deste curso para este operacional?\')">';
            wp_nonce_field('fieldflow_perf_reset_course_progress');
            echo '<input type="hidden" name="action" value="fieldflow_perf_reset_course_progress"><input type="hidden" name="user_id" value="'.esc_attr((string)$r['user_id']).'"><input type="hidden" name="course_id" value="'.esc_attr((string)$r['course_id']).'"><textarea name="reason" rows="2" style="width:100%;min-width:220px" required placeholder="Motivo obrigatório"></textarea><br><button class="button button-secondary" style="margin-top:6px">Reiniciar curso</button></form></td></tr>';
        }
        if(!$rows) echo '<tr><td colspan="6">Sem operacionais encontrados. Conclui uma lição, emite certificado ou confirma associação do utilizador à campanha/cliente.</td></tr>';
        echo '</tbody></table></div>';
        $logs = Module::get_reset_logs(40);
        echo '<div class="ffp-card ffp-table"><h2>Histórico de resets</h2><table class="widefat striped"><thead><tr><th>Data</th><th>Operacional</th><th>Curso</th><th>Motivo</th><th>Admin</th></tr></thead><tbody>';
        foreach($logs as $l){ echo '<tr><td>'.esc_html($l['created_at']).'</td><td>'.esc_html($l['display_name'] ?: ('User #'.(int)$l['user_id'])).'</td><td>'.esc_html($l['course_title'] ?: ('Curso #'.(int)$l['course_id'])).'</td><td>'.esc_html($l['reason']).'</td><td>'.esc_html($l['admin_name'] ?: '').'</td></tr>'; }
        if(!$logs) echo '<tr><td colspan="5">Ainda sem resets registados.</td></tr>';
        echo '</tbody></table></div>';
    }


    private static function skills(): void {
        $skills = Module::get_skills(true);
        $courses = Module::get_courses(['include_inactive'=>1]);
        $missions = Module::get_missions();
        $object_type = sanitize_key($_GET['object_type'] ?? 'course');
        if (!in_array($object_type, ['course','mission'], true)) $object_type = 'course';
        $object_id = absint($_GET['object_id'] ?? 0);
        if (!$object_id && $object_type === 'course' && $courses) $object_id = (int)$courses[0]['id'];
        if (!$object_id && $object_type === 'mission' && $missions) $object_id = (int)$missions[0]['id'];
        $rules = $object_id ? Module::get_skill_rules($object_type, $object_id) : [];
        $rule_points = [];
        foreach ($rules as $r) $rule_points[(int)$r['skill_id']] = (int)$r['points'];
        echo '<div class="ffp-card"><h2>Skill Assignment</h2><p class="ffp-muted">Define que competências cada curso ou missão desenvolve. A Skill Matrix do Growth Hub passa a calcular valores reais com base na conclusão de cursos, certificados e missões aprovadas.</p>';
        if (!empty($_GET['saved'])) echo '<div class="notice notice-success inline"><p>Competência guardada.</p></div>';
        if (!empty($_GET['rules_saved'])) echo '<div class="notice notice-success inline"><p>Regras de competências guardadas.</p></div>';
        echo '<div class="ffp-form-grid"><form method="post" action="'.esc_url(admin_url('admin-post.php')).'" class="ffp-card" style="box-shadow:none">';
        wp_nonce_field('fieldflow_perf_save_skill');
        echo '<input type="hidden" name="action" value="fieldflow_perf_save_skill"><h3>Nova competência</h3><p><label>Nome<br><input class="regular-text" name="name" placeholder="Ex: Negociação" required></label></p><p><label>Descrição<br><textarea name="description" rows="3" class="large-text"></textarea></label></p><p><label>Cor<br><input type="color" name="color" value="#0f172a"></label></p><p><label>Ordem<br><input type="number" name="sort_order" value="10"></label></p><p><button class="button button-primary">Guardar competência</button></p></form>';
        echo '<div class="ffp-card" style="box-shadow:none"><h3>Competências existentes</h3><table class="widefat striped"><thead><tr><th>Nome</th><th>Cor</th><th>Estado</th></tr></thead><tbody>';
        foreach($skills as $s){ echo '<tr><td><strong>'.esc_html($s['name']).'</strong><br><span class="ffp-muted">'.esc_html($s['description'] ?? '').'</span></td><td><span style="display:inline-block;width:18px;height:18px;border-radius:99px;background:'.esc_attr($s['color']).'"></span> '.esc_html($s['color']).'</td><td>'.esc_html($s['status']).'</td></tr>'; }
        if(!$skills) echo '<tr><td colspan="3">Sem competências.</td></tr>';
        echo '</tbody></table></div></div></div>';
        echo '<div class="ffp-card"><h2>Atribuir competências a cursos e missões</h2><form method="get" action="'.esc_url(admin_url('admin.php')).'"><input type="hidden" name="page" value="routespro-performance"><input type="hidden" name="tab" value="skills"><div class="ffp-form-grid"><p><label>Tipo<br><select name="object_type" onchange="this.form.submit()"><option value="course" '.selected($object_type,'course',false).'>Curso</option><option value="mission" '.selected($object_type,'mission',false).'>Missão</option></select></label></p><p><label>Item<br><select name="object_id" onchange="this.form.submit()">';
        $items = $object_type === 'course' ? $courses : $missions;
        foreach($items as $it){ echo '<option value="'.esc_attr($it['id']).'" '.selected($object_id,(int)$it['id'],false).'>'.esc_html($it['title']).'</option>'; }
        echo '</select></label></p><p style="align-self:end"><button class="button">Carregar</button></p></div></form>';
        if(!$skills){ echo '<p class="ffp-muted">Cria primeiro pelo menos uma competência.</p>'; }
        elseif(!$object_id){ echo '<p class="ffp-muted">Ainda não existem cursos ou missões para atribuir competências.</p>'; }
        else {
            echo '<form method="post" action="'.esc_url(admin_url('admin-post.php')).'">';
            wp_nonce_field('fieldflow_perf_save_skill_rules');
            echo '<input type="hidden" name="action" value="fieldflow_perf_save_skill_rules"><input type="hidden" name="object_type" value="'.esc_attr($object_type).'"><input type="hidden" name="object_id" value="'.esc_attr((string)$object_id).'">';
            echo '<table class="widefat striped"><thead><tr><th>Competência</th><th>Pontos</th><th>Nota</th></tr></thead><tbody>';
            foreach($skills as $s){ if(($s['status'] ?? '') !== 'active') continue; $sid=(int)$s['id']; echo '<tr><td><strong>'.esc_html($s['name']).'</strong><br><span class="ffp-muted">'.esc_html($s['description'] ?? '').'</span></td><td><input type="number" min="0" max="100" name="skill_points['.esc_attr((string)$sid).']" value="'.esc_attr((string)($rule_points[$sid] ?? 0)).'" style="width:90px"></td><td><span class="ffp-muted">0 remove a atribuição. Recomendado: 5 a 40 pontos.</span></td></tr>'; }
            echo '</tbody></table><p><button class="button button-primary">Guardar atribuições</button></p></form>';
            if($rules){ echo '<h3>Regras atuais</h3><table class="widefat striped"><thead><tr><th>Competência</th><th>Pontos</th></tr></thead><tbody>'; foreach($rules as $r){ echo '<tr><td>'.esc_html($r['skill_name']).'</td><td>'.esc_html((string)$r['points']).'</td></tr>'; } echo '</tbody></table>'; }
        }
        echo '</div>';
    }


    private static function activity_feed_admin(): void {
        $clients = Module::get_clients();
        $projects = Module::get_projects();
        $client_id = absint($_GET['client_id'] ?? 0);
        $project_id = absint($_GET['project_id'] ?? 0);
        $user_id = absint($_GET['user_id'] ?? 0);
        $page_no = max(1, absint($_GET['feed_page'] ?? 1));
        $per_page = 12;
        $scoped_ids = $user_id ? [$user_id] : Module::scope_user_ids($client_id, $project_id);
        $activity = Module::activity_feed($client_id, $project_id, $user_id, '', '', $scoped_ids);
        $total = count($activity);
        $pages = max(1, (int)ceil($total / $per_page));
        if ($page_no > $pages) $page_no = $pages;
        $slice = array_slice($activity, ($page_no - 1) * $per_page, $per_page);
        echo '<div class="ffp-card"><h2>Activity Feed</h2><p class="ffp-muted">Gestão administrativa do histórico visível no Growth Hub. Limpar o feed apenas oculta eventos antigos neste âmbito, não apaga progresso, certificados, badges, cursos ou missões.</p>';
        if (!empty($_GET['ffp_activity_cleared'])) echo '<div class="notice notice-success inline"><p>Activity Feed limpo para o âmbito selecionado.</p></div>';
        echo '<form method="get" action="'.esc_url(admin_url('admin.php')).'"><input type="hidden" name="page" value="routespro-performance"><input type="hidden" name="tab" value="activity"><div class="ffp-form-grid">';
        echo '<p><label>Cliente<br><select name="client_id"><option value="0">Todos</option>'; foreach($clients as $c) echo '<option value="'.esc_attr($c['id']).'" '.selected($client_id,(int)$c['id'],false).'>'.esc_html($c['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>Campanha<br><select name="project_id"><option value="0">Todas</option>'; foreach($projects as $p) echo '<option value="'.esc_attr($p['id']).'" '.selected($project_id,(int)$p['id'],false).'>'.esc_html($p['name']).'</option>'; echo '</select></label></p>';
        echo '<p><label>User ID opcional<br><input type="number" name="user_id" value="'.esc_attr((string)$user_id).'" placeholder="Ex: 12"></label></p>';
        echo '<p style="align-self:end"><button class="button button-primary">Filtrar</button> <a class="button" href="'.esc_url(admin_url('admin.php?page=routespro-performance&tab=activity')).'">Limpar filtros</a></p></div></form>';
        echo '<form method="post" action="'.esc_url(admin_url('admin-post.php')).'" onsubmit="return confirm(\'Limpar a Activity Feed deste âmbito? Isto apenas oculta eventos antigos, não apaga progresso, certificados ou missões.\');" style="margin-top:10px">';
        wp_nonce_field('fieldflow_perf_clear_activity');
        echo '<input type="hidden" name="action" value="fieldflow_perf_clear_activity"><input type="hidden" name="client_id" value="'.esc_attr((string)$client_id).'"><input type="hidden" name="project_id" value="'.esc_attr((string)$project_id).'"><button class="button button-secondary">Limpar feed deste âmbito</button></form></div>';
        echo '<div class="ffp-card ffp-table"><h2>Eventos recentes</h2><p class="ffp-muted">A mostrar '.esc_html((string)count($slice)).' de '.esc_html((string)$total).' eventos.</p><table class="widefat striped"><thead><tr><th>Evento</th><th>Item</th><th>Utilizador</th><th>Data</th></tr></thead><tbody>';
        foreach($slice as $a){ echo '<tr><td><strong>'.esc_html($a['label']).'</strong></td><td>'.esc_html($a['item']).'</td><td>'.esc_html($a['display_name']).'</td><td>'.esc_html($a['date_label']).'</td></tr>'; }
        if(!$slice) echo '<tr><td colspan="4">Sem eventos neste âmbito.</td></tr>';
        echo '</tbody></table>';
        if($pages > 1){ echo '<p style="margin-top:14px">'; for($i=1;$i<=$pages;$i++){ $url=add_query_arg(['page'=>'routespro-performance','tab'=>'activity','client_id'=>$client_id,'project_id'=>$project_id,'user_id'=>$user_id,'feed_page'=>$i], admin_url('admin.php')); echo '<a class="button '.($i===$page_no?'button-primary':'').'" style="margin-right:4px" href="'.esc_url($url).'">'.esc_html((string)$i).'</a>'; } echo '</p>'; }
        echo '</div>';
    }

    private static function shortcodes(): void {
        echo '<div class="ffp-card"><h2>Shortcodes Growth Hub</h2><table class="widefat striped"><thead><tr><th>Shortcode</th><th>Função</th></tr></thead><tbody>';
        echo '<tr><td><code>[fieldflow_performance_dashboard]</code></td><td>Dashboard Growth Hub front para cliente ou campanha.</td></tr><tr><td><code>[fieldflow_academy]</code></td><td>Área de formação e missões para pessoas de terreno.</td></tr><tr><td><code>[fieldflow_client_portal]</code></td><td>Inclui a aba Growth Hub automaticamente.</td></tr><tr><td><code>[fieldflow_app]</code></td><td>Inclui a aba Academy automaticamente.</td></tr><tr><td><strong>Automações</strong></td><td>Regras que ligam respostas de reportes a missões, cursos e emails.</td></tr>';
        echo '</tbody></table></div>';
    }
}
